import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Filter, Calendar, Tag, Trash2, X, Save, User } from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Despesas.css'; // O CSS deve ser unificado ou compartilhar classes

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [responsaveis, setResponsaveis] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState(null);
  const navigate = useNavigate();

  const [feedback, setFeedback] = useState({
    isOpen: false, type: 'success', title: '', message: '', onConfirm: null
  });

  useEffect(() => { buscarDados(); }, []);

  const alertar = (type, title, message, onConfirm = null) => {
    setFeedback({ isOpen: true, type, title, message, onConfirm });
  };

  async function buscarDados() {
    setLoading(true);
    try {
      const { data } = await supabase.from('compras').select(`*, categorias (nome, cor)`).eq('tipo_despesa', 'Gastos Variáveis').order('data_compra', { ascending: false });
      const { data: dataCat } = await supabase.from('categorias').select('*').order('nome', { ascending: true });
      const { data: dataProf } = await supabase.from('profiles').select('id, nome').order('nome', { ascending: true });
      
      setDespesas(data || []);
      setCategorias(dataCat || []);
      setResponsaveis(dataProf || []);
    } catch (error) { console.error(error); } finally { setLoading(false); }
  }

  const formatarMoeda = (valor) => Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  const handleMascaraMoeda = (e) => {
    let valor = e.target.value.replace(/\D/g, "");
    const valorNumerico = (Number(valor) / 100).toFixed(2);
    setItemEditando({ ...itemEditando, valor_exibicao: formatarMoeda(valorNumerico) });
  };

  const handleAbrirModal = (item) => {
    setItemEditando({ ...item, valor_exibicao: formatarMoeda(item.valor_total) });
    setIsModalOpen(true);
  };

  const handleSalvarEdicao = async (e) => {
    e.preventDefault();
    try {
      const valorLimpo = Number(itemEditando.valor_exibicao.replace(/[^\d,]/g, '').replace(',', '.'));
      const { error } = await supabase.from('compras').update({
        descricao: itemEditando.descricao, valor_total: valorLimpo, data_compra: itemEditando.data_compra,
        categoria_id: itemEditando.categoria_id, user_id: itemEditando.user_id
      }).eq('id', itemEditando.id);

      if (error) throw error;
      setIsModalOpen(false);
      buscarDados();
      alertar('success', 'Sucesso', 'Despesa atualizada!');
    } catch (error) { alertar('error', 'Erro', error.message); }
  };

  return (
    <div className="finance-wrapper theme-red">
      <div className="finance-top-layout">
        <header className="finance-panel finance-header">
          <div className="title-area">
            <h1>Despesas</h1>
            <p>Pagamentos e Gastos Variáveis</p>
          </div>
          <button className="filter-btn"><Filter size={20} /></button>
        </header>

        <div className="finance-panel summary-card">
          <span className="summary-label">Total Saídas</span>
          <h2 className="summary-value">{formatarMoeda(despesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}</h2>
        </div>
      </div>

      <main className="finance-panel list-panel">
        <div className="list-header"><h3>Movimentações</h3></div>
        <div className="finance-list">
          {loading ? <div className="loading">Carregando...</div> : despesas.map((item) => (
            <div key={item.id} className="item-row" onClick={() => handleAbrirModal(item)}>
              <div className="left-content">
                <div className="indicator" style={{ backgroundColor: item.categorias?.cor }}></div>
                <div className="details">
                  <span className="desc">{item.descricao}</span>
                  <div className="meta">
                    <span className="meta-tag"><Calendar size={12} /> {new Date(item.data_compra).toLocaleDateString('pt-BR', {timeZone: 'UTC'})}</span>
                    <span className="meta-tag"><Tag size={12} /> {item.categorias?.nome}</span>
                  </div>
                </div>
              </div>
              <span className="item-value value-negative">{formatarMoeda(item.valor_total)}</span>
            </div>
          ))}
        </div>
      </main>

      {isModalOpen && itemEditando && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
          <div className="finance-modal" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Editar Despesa</h2>
              <button onClick={() => setIsModalOpen(false)} className="close-btn"><X size={20} /></button>
            </div>
            <form onSubmit={handleSalvarEdicao} className="finance-form">
              <div className="form-group"><label>DESCRIÇÃO</label>
                <input type="text" value={itemEditando.descricao} onChange={e => setItemEditando({...itemEditando, descricao: e.target.value})} required />
              </div>
              <div className="form-row">
                <div className="form-group"><label>VALOR</label>
                  <input type="text" value={itemEditando.valor_exibicao} onChange={handleMascaraMoeda} required />
                </div>
                <div className="form-group"><label>DATA</label>
                  <input type="date" value={itemEditando.data_compra} onChange={e => setItemEditando({...itemEditando, data_compra: e.target.value})} required />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>CATEGORIA</label>
                  <select value={itemEditando.categoria_id} onChange={e => setItemEditando({...itemEditando, categoria_id: e.target.value})}>
                    {categorias.map(cat => <option key={cat.id} value={cat.id}>{cat.nome}</option>)}
                  </select>
                </div>
                <div className="form-group"><label>RESPONSÁVEL</label>
                  <select value={itemEditando.user_id} onChange={e => setItemEditando({...itemEditando, user_id: e.target.value})} required>
                    <option value="">Selecione...</option>
                    {responsaveis.map(resp => <option key={resp.id} value={resp.id}>{resp.nome}</option>)}
                  </select>
                </div>
              </div>
              <div className="modal-actions">
                <button type="submit" className="btn-main"><Save size={18} /> Salvar</button>
                <button type="button" className="btn-secondary" onClick={() => alertar('danger', 'Excluir?', 'Deseja apagar?', () => {/* delete */})}>
                  <Trash2 size={18} /> Excluir
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
      <button className="fab-btn" onClick={() => navigate('/lancamento')}><Plus size={30} /></button>
      <ModalFeedback {...feedback} onClose={() => setFeedback({ ...feedback, isOpen: false })} />
    </div>
  );
};
export default Despesas;
